    const cells = [...row.matchAll(/<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi)].map((match) => strip(match[1]));
    if (cells.length < 3) continue;
    const first = cells[0] || '';
    if (!/^\d+$/.test(first)) continue;
    const rank = Number(first);
    const bank = cells[1] || '';
    const name = cells[2] || '';
    const returnCell = cells.find((cell, index) => index >= 3 && /%/.test(cell)) || cells[cells.length - 1];
    const return1y = parsePercent(returnCell);
    const hrefMatch = row.match(/fund[_-]?id=(\d+)/i);
    const fundId = hrefMatch ? Number(hrefMatch[1]) : null;
    if (name && Number.isFinite(return1y)) parsed.push({ rank, bank, fund_id: fundId, name, navpu: null, return_1y: return1y });
  }
  return parsed;
}
function parseTextRows(text) {
  const parsed = [];
  const lines = String(text || '').split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  for (let i = 0; i < lines.length; i += 1) {
    const line = lines[i];
    const pipeCells = line.includes('|') ? line.split('|').map((cell) => strip(cell)).filter(Boolean) : [];
    if (pipeCells.length >= 4 && /^\d+$/.test(pipeCells[0]) && /%/.test(pipeCells[pipeCells.length - 1])) {
      const return1y = parsePercent(pipeCells[pipeCells.length - 1]);
      if (Number.isFinite(return1y)) parsed.push({ rank: Number(pipeCells[0]), bank: pipeCells[1], name: pipeCells[2], navpu: null, return_1y: return1y });
      continue;
    }
    const compactMatch = line.match(/^\s*(\d+)\s+(.+?)\s{2,}(.+?)\s+(-?\d+(?:\.\d+)?)%\s*$/);
    if (compactMatch) {
      parsed.push({ rank: Number(compactMatch[1]), bank: strip(compactMatch[2]), name: strip(compactMatch[3]), navpu: null, return_1y: Number(compactMatch[4]) });
